class Solution {
    vector<int> p;
    int find(int x){ return p[x]==x?x:p[x]=find(p[x]); }
public:
    vector<int> findRedundantConnection(vector<vector<int>>& e) {
        p.resize(e.size()+1); iota(p.begin(),p.end(),0);
        for(auto& ed:e){
            int u=find(ed[0]), v=find(ed[1]);
            if(u==v) return ed;
            p[u]=v;
        }
        return {};
    }
};
